mapper.select:
SELECT *
FROM hospital_announcement
WHERE dept_id = #{deptId}
ORDER BY publish_date DESC
LIMIT #{limit}

SELECT *
FROM hospital_announcement
WHERE dept_id = 0 OR dept_id = #{deptId}
ORDER BY publish_date DESC
LIMIT #{limit}

SELECT * FROM hospital_announcement WHERE 1 = 1
AND priority = #{priority}
AND (dept_id = 0 OR dept_id = #{deptId})
ORDER BY publish_date DESC LIMIT #{limit}
